export * from "./categories";
export * from "./products";
export * from "./orders";

import { Router } from "express";
import { db, categoriesTable, productsTable } from "@workspace/db";
import { eq, count } from "drizzle-orm";

const router = Router();

router.get("/categories", async (req, res) => {
  const cats = await db
    .select({
      id: categoriesTable.id,
      name: categoriesTable.name,
      productCount: count(productsTable.id),
    })
    .from(categoriesTable)
    .leftJoin(productsTable, eq(productsTable.categoryId, categoriesTable.id))
    .groupBy(categoriesTable.id, categoriesTable.name);
  res.json(cats);
});

router.post("/categories", async (req, res) => {
  const { name } = req.body as { name: string };
  if (!name?.trim()) {
    res.status(400).json({ error: "name is required" });
    return;
  }
  const [cat] = await db.insert(categoriesTable).values({ name: name.trim() }).returning();
  res.status(201).json({ ...cat, productCount: 0 });
});

router.patch("/categories/:id", async (req, res) => {
  const id = Number(req.params["id"]);
  const { name } = req.body as { name?: string };
  const update: Partial<{ name: string }> = {};
  if (name !== undefined) update.name = name.trim();
  if (Object.keys(update).length === 0) {
    res.status(400).json({ error: "No fields to update" });
    return;
  }
  const [cat] = await db.update(categoriesTable).set(update).where(eq(categoriesTable.id, id)).returning();
  if (!cat) {
    res.status(404).json({ error: "Not found" });
    return;
  }
  const [{ productCount }] = await db
    .select({ productCount: count(productsTable.id) })
    .from(productsTable)
    .where(eq(productsTable.categoryId, id));
  res.json({ ...cat, productCount });
});

router.delete("/categories/:id", async (req, res) => {
  const id = Number(req.params["id"]);
  await db.delete(categoriesTable).where(eq(categoriesTable.id, id));
  res.status(204).send();
});

export default router;

import { Router } from "express";
import { db, productsTable, categoriesTable } from "@workspace/db";
import { eq, ilike, and, type SQL } from "drizzle-orm";

const router = Router();

const toProduct = (row: {
  id: number;
  name: string;
  categoryId: number | null;
  price: string;
  stock: number;
  imageUrl: string | null;
  isActive: boolean;
  categoryName: string | null;
}) => ({
  id: row.id,
  name: row.name,
  categoryId: row.categoryId,
  categoryName: row.categoryName,
  price: parseFloat(row.price),
  stock: row.stock,
  imageUrl: row.imageUrl,
  isActive: row.isActive,
});

router.get("/products", async (req, res) => {
  const { categoryId, search, active } = req.query as {
    categoryId?: string;
    search?: string;
    active?: string;
  };

  const conditions: SQL[] = [];
  if (categoryId) conditions.push(eq(productsTable.categoryId, Number(categoryId)));
  if (active !== undefined) conditions.push(eq(productsTable.isActive, active === "true"));
  if (search) conditions.push(ilike(productsTable.name, `%${search}%`));

  const rows = await db
    .select({
      id: productsTable.id,
      name: productsTable.name,
      categoryId: productsTable.categoryId,
      price: productsTable.price,
      stock: productsTable.stock,
      imageUrl: productsTable.imageUrl,
      isActive: productsTable.isActive,
      categoryName: categoriesTable.name,
    })
    .from(productsTable)
    .leftJoin(categoriesTable, eq(categoriesTable.id, productsTable.categoryId))
    .where(conditions.length ? and(...conditions) : undefined);

  res.json(rows.map(toProduct));
});

router.post("/products", async (req, res) => {
  const { name, categoryId, price, stock, imageUrl, isActive } = req.body as {
    name: string;
    categoryId?: number | null;
    price: number;
    stock?: number;
    imageUrl?: string | null;
    isActive?: boolean;
  };
  if (!name?.trim() || price == null) {
    res.status(400).json({ error: "name and price are required" });
    return;
  }
  const [prod] = await db
    .insert(productsTable)
    .values({
      name: name.trim(),
      categoryId: categoryId ?? null,
      price: String(price),
      stock: stock ?? 0,
      imageUrl: imageUrl ?? null,
      isActive: isActive ?? true,
    })
    .returning();

  let categoryName: string | null = null;
  if (prod.categoryId) {
    const [cat] = await db.select().from(categoriesTable).where(eq(categoriesTable.id, prod.categoryId));
    categoryName = cat?.name ?? null;
  }

  res.status(201).json(toProduct({ ...prod, categoryName }));
});

router.get("/products/:id", async (req, res) => {
  const id = Number(req.params["id"]);
  const [row] = await db
    .select({
      id: productsTable.id,
      name: productsTable.name,
      categoryId: productsTable.categoryId,
      price: productsTable.price,
      stock: productsTable.stock,
      imageUrl: productsTable.imageUrl,
      isActive: productsTable.isActive,
      categoryName: categoriesTable.name,
    })
    .from(productsTable)
    .leftJoin(categoriesTable, eq(categoriesTable.id, productsTable.categoryId))
    .where(eq(productsTable.id, id));
  if (!row) {
    res.status(404).json({ error: "Not found" });
    return;
  }
  res.json(toProduct(row));
});

router.patch("/products/:id", async (req, res) => {
  const id = Number(req.params["id"]);
  const { name, categoryId, price, stock, imageUrl, isActive } = req.body as {
    name?: string;
    categoryId?: number | null;
    price?: number;
    stock?: number;
    imageUrl?: string | null;
    isActive?: boolean;
  };
  const update: Record<string, unknown> = {};
  if (name !== undefined) update["name"] = name.trim();
  if (categoryId !== undefined) update["categoryId"] = categoryId;
  if (price !== undefined) update["price"] = String(price);
  if (stock !== undefined) update["stock"] = stock;
  if (imageUrl !== undefined) update["imageUrl"] = imageUrl;
  if (isActive !== undefined) update["isActive"] = isActive;

  if (Object.keys(update).length === 0) {
    res.status(400).json({ error: "No fields to update" });
    return;
  }

  const [prod] = await db.update(productsTable).set(update).where(eq(productsTable.id, id)).returning();
  if (!prod) {
    res.status(404).json({ error: "Not found" });
    return;
  }

  let categoryName: string | null = null;
  if (prod.categoryId) {
    const [cat] = await db.select().from(categoriesTable).where(eq(categoriesTable.id, prod.categoryId));
    categoryName = cat?.name ?? null;
  }

  res.json(toProduct({ ...prod, categoryName }));
});

router.delete("/products/:id", async (req, res) => {
  const id = Number(req.params["id"]);
  await db.delete(productsTable).where(eq(productsTable.id, id));
  res.status(204).send();
});

export default router;

import { Router } from "express";
import { db, ordersTable, orderItemsTable, productsTable } from "@workspace/db";
import { eq, and, gte, lte, count, sql } from "drizzle-orm";

const router = Router();

const toOrder = (row: typeof ordersTable.$inferSelect & { itemCount?: number }) => ({
  id: row.id,
  cashierName: row.cashierName,
  total: parseFloat(row.total),
  amountPaid: parseFloat(row.amountPaid),
  change: parseFloat(row.change),
  paymentMethod: row.paymentMethod,
  status: row.status,
  createdAt: row.createdAt.toISOString(),
  itemCount: row.itemCount ?? 0,
});

router.get("/orders", async (req, res) => {
  const { date, status } = req.query as { date?: string; status?: string };
  const conditions = [];
  if (date) {
    const start = new Date(date);
    start.setHours(0, 0, 0, 0);
    const end = new Date(date);
    end.setHours(23, 59, 59, 999);
    conditions.push(gte(ordersTable.createdAt, start));
    conditions.push(lte(ordersTable.createdAt, end));
  }
  if (status) conditions.push(eq(ordersTable.status, status));

  const rows = await db
    .select({
      id: ordersTable.id,
      cashierName: ordersTable.cashierName,
      total: ordersTable.total,
      amountPaid: ordersTable.amountPaid,
      change: ordersTable.change,
      paymentMethod: ordersTable.paymentMethod,
      status: ordersTable.status,
      createdAt: ordersTable.createdAt,
      itemCount: count(orderItemsTable.id),
    })
    .from(ordersTable)
    .leftJoin(orderItemsTable, eq(orderItemsTable.orderId, ordersTable.id))
    .where(conditions.length ? and(...conditions) : undefined)
    .groupBy(ordersTable.id)
    .orderBy(sql`${ordersTable.createdAt} desc`);

  res.json(rows.map(toOrder));
});

router.post("/orders", async (req, res) => {
  const { cashierName, paymentMethod, amountPaid, items } = req.body as {
    cashierName?: string;
    paymentMethod: string;
    amountPaid: number;
    items: Array<{ productId: number; quantity: number }>;
  };

  if (!items?.length) {
    res.status(400).json({ error: "items are required" });
    return;
  }

  let total = 0;
  const itemRows: Array<{
    productId: number;
    productName: string;
    quantity: number;
    priceAtSale: string;
    subtotal: string;
  }> = [];

  for (const item of items) {
    const [prod] = await db
      .select()
      .from(productsTable)
      .where(eq(productsTable.id, item.productId));
    if (!prod) {
      res.status(400).json({ error: `Product ${item.productId} not found` });
      return;
    }
    const price = parseFloat(prod.price);
    const subtotal = price * item.quantity;
    total += subtotal;
    itemRows.push({
      productId: prod.id,
      productName: prod.name,
      quantity: item.quantity,
      priceAtSale: String(price),
      subtotal: String(subtotal),
    });

    await db
      .update(productsTable)
      .set({ stock: Math.max(0, prod.stock - item.quantity) })
      .where(eq(productsTable.id, prod.id));
  }

  const change = Math.max(0, amountPaid - total);
  const [order] = await db
    .insert(ordersTable)
    .values({
      cashierName: cashierName ?? null,
      total: String(total),
      amountPaid: String(amountPaid),
      change: String(change),
      paymentMethod: paymentMethod ?? "cash",
      status: "completed",
    })
    .returning();

  await db.insert(orderItemsTable).values(
    itemRows.map((r) => ({ ...r, orderId: order.id }))
  );

  res.status(201).json(toOrder({ ...order, itemCount: itemRows.length }));
});

router.get("/orders/:id", async (req, res) => {
  const id = Number(req.params["id"]);
  const [order] = await db.select().from(ordersTable).where(eq(ordersTable.id, id));
  if (!order) {
    res.status(404).json({ error: "Not found" });
    return;
  }
  const items = await db
    .select()
    .from(orderItemsTable)
    .where(eq(orderItemsTable.orderId, id));

  res.json({
    ...toOrder({ ...order, itemCount: items.length }),
    items: items.map((i) => ({
      id: i.id,
      productId: i.productId,
      productName: i.productName,
      quantity: i.quantity,
      priceAtSale: parseFloat(i.priceAtSale),
      subtotal: parseFloat(i.subtotal),
    })),
  });
});

export default router;

import { Router } from "express";
import { db, ordersTable, orderItemsTable, productsTable } from "@workspace/db";
import { eq, gte, lte, and, sum, count, sql } from "drizzle-orm";

const router = Router();

router.get("/dashboard/summary", async (req, res) => {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const todayEnd = new Date();
  todayEnd.setHours(23, 59, 59, 999);

  const yesterday = new Date(today);
  yesterday.setDate(yesterday.getDate() - 1);
  const yesterdayEnd = new Date(todayEnd);
  yesterdayEnd.setDate(yesterdayEnd.getDate() - 1);

  const [todayStats] = await db
    .select({
      revenue: sum(ordersTable.total),
      orders: count(ordersTable.id),
    })
    .from(ordersTable)
    .where(and(gte(ordersTable.createdAt, today), lte(ordersTable.createdAt, todayEnd)));

  const [yesterdayStats] = await db
    .select({
      revenue: sum(ordersTable.total),
      orders: count(ordersTable.id),
    })
    .from(ordersTable)
    .where(and(gte(ordersTable.createdAt, yesterday), lte(ordersTable.createdAt, yesterdayEnd)));

  const [productCounts] = await db
    .select({ total: count(productsTable.id), lowStock: sql<number>`sum(case when ${productsTable.stock} <= 5 then 1 else 0 end)` })
    .from(productsTable)
    .where(eq(productsTable.isActive, true));

  const todayRevenue = parseFloat(todayStats?.revenue ?? "0");
  const todayOrders = todayStats?.orders ?? 0;
  const yRevenue = parseFloat(yesterdayStats?.revenue ?? "0");
  const yOrders = yesterdayStats?.orders ?? 0;

  res.json({
    todayRevenue,
    todayOrders,
    totalProducts: productCounts?.total ?? 0,
    lowStockCount: Number(productCounts?.lowStock ?? 0),
    todayRevenueDiff: yRevenue > 0 ? ((todayRevenue - yRevenue) / yRevenue) * 100 : 0,
    todayOrdersDiff: yOrders > 0 ? ((todayOrders - yOrders) / yOrders) * 100 : 0,
  });
});

router.get("/dashboard/top-products", async (req, res) => {
  const limit = Number(req.query["limit"] ?? 5);
  const rows = await db
    .select({
      productId: orderItemsTable.productId,
      productName: orderItemsTable.productName,
      totalSold: sum(orderItemsTable.quantity),
      totalRevenue: sum(orderItemsTable.subtotal),
    })
    .from(orderItemsTable)
    .groupBy(orderItemsTable.productId, orderItemsTable.productName)
    .orderBy(sql`sum(${orderItemsTable.quantity}) desc`)
    .limit(limit);

  res.json(
    rows.map((r) => ({
      productId: r.productId,
      productName: r.productName,
      totalSold: Number(r.totalSold ?? 0),
      totalRevenue: parseFloat(r.totalRevenue ?? "0"),
    }))
  );
});

router.get("/dashboard/sales-chart", async (req, res) => {
  const days: { date: string; revenue: number; orders: number }[] = [];
  for (let i = 6; i >= 0; i--) {
    const d = new Date();
    d.setDate(d.getDate() - i);
    d.setHours(0, 0, 0, 0);
    const dEnd = new Date(d);
    dEnd.setHours(23, 59, 59, 999);

    const [stats] = await db
      .select({ revenue: sum(ordersTable.total), orders: count(ordersTable.id) })
      .from(ordersTable)
      .where(and(gte(ordersTable.createdAt, d), lte(ordersTable.createdAt, dEnd)));

    days.push({
      date: d.toISOString().split("T")[0],
      revenue: parseFloat(stats?.revenue ?? "0"),
      orders: stats?.orders ?? 0,
    });
  }
  res.json(days);
});

export default router;

import { Router, type IRouter } from "express";
import healthRouter from "./health";
import categoriesRouter from "./categories";
import productsRouter from "./products";
import ordersRouter from "./orders";
import dashboardRouter from "./dashboard";

const router: IRouter = Router();

router.use(healthRouter);
router.use(categoriesRouter);
router.use(productsRouter);
router.use(ordersRouter);
router.use(dashboardRouter);

export default router;

