                    </AreaChart>
                  </ResponsiveContainer>
                )}
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="pb-2">
                <CardTitle className="text-base font-semibold">Transaksi per Hari</CardTitle>
              </CardHeader>
              <CardContent>
                {loadingChart ? (
                  <div className="h-56 bg-muted/50 rounded-lg animate-pulse" />
