import { pgTable, serial, text, timestamp } from "drizzle-orm/pg-core";
import { createInsertSchema } from "drizzle-zod";
import { z } from "zod/v4";

export const branchesTable = pgTable("branches", {
  id: serial("id").primaryKey(),
  name: text("name").notNull(),
  location: text("location"),
  createdAt: timestamp("created_at", { withTimezone: true }).notNull().defaultNow(),
});

export const insertBranchSchema = createInsertSchema(branchesTable).omit({ id: true, createdAt: true });
export type InsertBranch = z.infer<typeof insertBranchSchema>;
export type Branch = typeof branchesTable.$inferSelect;

import { pgTable, serial, text, integer, numeric, timestamp } from "drizzle-orm/pg-core";
import { createInsertSchema } from "drizzle-zod";
import { z } from "zod/v4";
import { branchesTable } from "./branches";

// Raw materials (bahan mentah)
export const ingredientsTable = pgTable("ingredients", {
  id: serial("id").primaryKey(),
  branchId: integer("branch_id")
    .notNull()
    .references(() => branchesTable.id, { onDelete: "cascade" }),
  name: text("name").notNull(),
  unit: text("unit").notNull().default("gram"), // gram | ml | pcs
  costPricePerUnit: numeric("cost_price_per_unit", { precision: 14, scale: 4 })
    .notNull()
    .default("0"),
  minimalStock: numeric("minimal_stock", { precision: 14, scale: 2 }).notNull().default("0"),
  createdAt: timestamp("created_at", { withTimezone: true }).notNull().defaultNow(),
});

export const insertIngredientSchema = createInsertSchema(ingredientsTable).omit({
  id: true,
  createdAt: true,
});
export type InsertIngredient = z.infer<typeof insertIngredientSchema>;
export type Ingredient = typeof ingredientsTable.$inferSelect;

import { pgTable, serial, text, integer, numeric, timestamp } from "drizzle-orm/pg-core";
import { createInsertSchema } from "drizzle-zod";
import { z } from "zod/v4";
import { branchesTable } from "./branches";

// Semi-finished goods (bahan setengah jadi)
export const semiFinishedTable = pgTable("semi_finished", {
  id: serial("id").primaryKey(),
  branchId: integer("branch_id")
    .notNull()
    .references(() => branchesTable.id, { onDelete: "cascade" }),
  name: text("name").notNull(),
  unit: text("unit").notNull().default("gram"), // gram | ml | pcs
  costPricePerUnit: numeric("cost_price_per_unit", { precision: 14, scale: 4 })
    .notNull()
    .default("0"),
  createdAt: timestamp("created_at", { withTimezone: true }).notNull().defaultNow(),
});

export const insertSemiFinishedSchema = createInsertSchema(semiFinishedTable).omit({
  id: true,
  createdAt: true,
});
export type InsertSemiFinished = z.infer<typeof insertSemiFinishedSchema>;
export type SemiFinished = typeof semiFinishedTable.$inferSelect;

import { pgTable, serial, text, integer, numeric } from "drizzle-orm/pg-core";
import { createInsertSchema } from "drizzle-zod";
import { z } from "zod/v4";

// Bill of Materials (BOM). A parent (finished product OR semi-finished good)
// is composed of components (raw ingredients OR semi-finished goods).
export const recipesTable = pgTable("recipes", {
  id: serial("id").primaryKey(),
  parentType: text("parent_type").notNull(), // 'product' | 'semi_finished'
  parentId: integer("parent_id").notNull(),
  componentType: text("component_type").notNull(), // 'ingredient' | 'semi_finished'
  componentId: integer("component_id").notNull(),
  quantity: numeric("quantity", { precision: 14, scale: 4 }).notNull(), // takaran per 1 parent
});

export const insertRecipeSchema = createInsertSchema(recipesTable).omit({ id: true });
export type InsertRecipe = z.infer<typeof insertRecipeSchema>;
export type Recipe = typeof recipesTable.$inferSelect;

import { pgTable, serial, text, integer, numeric, timestamp, unique } from "drizzle-orm/pg-core";
import { createInsertSchema } from "drizzle-zod";
import { z } from "zod/v4";
import { branchesTable } from "./branches";

// Live stock level per item per branch.
export const currentInventoryTable = pgTable(
  "current_inventory",
  {
    id: serial("id").primaryKey(),
    branchId: integer("branch_id")
      .notNull()
      .references(() => branchesTable.id, { onDelete: "cascade" }),
    itemType: text("item_type").notNull(), // 'ingredient' | 'semi_finished'
    itemId: integer("item_id").notNull(),
    currentStock: numeric("current_stock", { precision: 14, scale: 2 }).notNull().default("0"),
  },
  (t) => [unique("uniq_inventory_item").on(t.branchId, t.itemType, t.itemId)],
);

// Ledger of every stock movement.
export const stockAdjustmentsTable = pgTable("stock_adjustments", {
  id: serial("id").primaryKey(),
  branchId: integer("branch_id")
    .notNull()
    .references(() => branchesTable.id, { onDelete: "cascade" }),
  itemType: text("item_type").notNull(), // 'ingredient' | 'semi_finished'
  itemId: integer("item_id").notNull(),
  adjustmentType: text("adjustment_type").notNull(), // 'in' | 'out' | 'loss'
  quantity: numeric("quantity", { precision: 14, scale: 2 }).notNull(),
  purchasePriceTotal: numeric("purchase_price_total", { precision: 14, scale: 2 }),
  notes: text("notes"),
  createdAt: timestamp("created_at", { withTimezone: true }).notNull().defaultNow(),
});

export const insertCurrentInventorySchema = createInsertSchema(currentInventoryTable).omit({
  id: true,
});
export const insertStockAdjustmentSchema = createInsertSchema(stockAdjustmentsTable).omit({
