   103→function ClerkQueryCacheInvalidator() {
   104→  const { addListener } = useClerk();
   105→  const qc = useQueryClient();
   106→  const prevRef = useRef<string | null | undefined>(undefined);
   107→
   108→  useEffect(() => {
   109→    const unsub = addListener(({ user }) => {
   110→      const uid = user?.id ?? null;
   111→      if (prevRef.current !== undefined && prevRef.current !== uid) qc.clear();
   112→      prevRef.current = uid;
   113→    });
   114→    return unsub;
   115→  }, [addListener, qc]);
   116→
   117→  return null;
   118→}
