  const [minStock, setMinStock] = useState("");

  const submit = () => {
    if (!branchId) return;
    if (!name.trim() || !unit.trim()) { toast.error("Nama dan satuan wajib diisi"); return; }
    createIng.mutate(
      { data: { branchId, name: name.trim(), unit: unit.trim(), minimalStock: minStock ? parseFloat(minStock) : undefined } },
      {
        onSuccess: () => {
          toast.success("Bahan baku ditambahkan");
          setOpen(false); setName(""); setUnit(""); setMinStock("");
          qc.invalidateQueries({ queryKey: getListIngredientsQueryKey({ branchId }) });
          qc.invalidateQueries({ queryKey: getListInventoryQueryKey({ branchId }) });
        },
        onError: () => toast.error("Gagal menambah bahan baku"),
      },
    );
  };

  return (
    <ScrollArea className="h-full">
      <div className="p-6 space-y-3">
        <div className="flex justify-end">
          <Button size="sm" onClick={() => setOpen(true)}><Plus className="w-4 h-4 mr-1.5" />Tambah Bahan</Button>
        </div>
        {isLoading ? (
          [1, 2, 3].map((i) => <div key={i} className="h-14 rounded-lg bg-muted animate-pulse" />)
        ) : ingredients.length === 0 ? (
          <Empty icon={Package} text="Belum ada bahan baku" />
        ) : (
          ingredients.map((ing) => (
            <Card key={ing.id}>
              <CardContent className="p-4 flex items-center gap-4">
                <div className="w-9 h-9 rounded-lg bg-primary/10 text-primary flex items-center justify-center shrink-0"><Package className="w-4 h-4" /></div>
                <div className="flex-1 min-w-0">
                  <span className="font-medium">{ing.name}</span>
                  <p className="text-xs text-muted-foreground">HPP {formatRp(ing.costPricePerUnit)} / {ing.unit} · Min {ing.minimalStock}</p>
                </div>
                <div className="text-right">
                  <p className="font-bold">{ing.currentStock}</p>
                  <p className="text-[11px] text-muted-foreground">{ing.unit}</p>
                </div>
              </CardContent>
            </Card>
          ))
        )}
      </div>

      <Dialog open={open} onOpenChange={setOpen}>
        <DialogContent>
          <DialogHeader><DialogTitle>Tambah Bahan Baku</DialogTitle></DialogHeader>
          <div className="space-y-4 py-2">
            <div className="space-y-1.5"><label className="text-sm font-medium">Nama</label><Input value={name} onChange={(e) => setName(e.target.value)} placeholder="cth. Kopi Arabika" autoFocus /></div>
            <div className="space-y-1.5"><label className="text-sm font-medium">Satuan</label><Input value={unit} onChange={(e) => setUnit(e.target.value)} placeholder="cth. gram, ml, pcs" /></div>
            <div className="space-y-1.5"><label className="text-sm font-medium">Stok Minimal (alert)</label><Input type="number" value={minStock} onChange={(e) => setMinStock(e.target.value)} placeholder="200" /></div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setOpen(false)}>Batal</Button>
            <Button onClick={submit} disabled={createIng.isPending}>{createIng.isPending ? "Menyimpan..." : "Simpan"}</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </ScrollArea>
  );
}

function SemiFinishedTab({ branchId }: { branchId: number | null }) {
  const qc = useQueryClient();
  const { data: items = [], isLoading } = useListSemiFinished(
    branchId ? { branchId } : undefined,
    { query: { enabled: branchId != null } },
  );
  const createSf = useCreateSemiFinished();
  const produce = useProduceSemiFinished();
  const [open, setOpen] = useState(false);
  const [name, setName] = useState("");
  const [unit, setUnit] = useState("");
  const [recipeFor, setRecipeFor] = useState<{ id: number; name: string } | null>(null);
  const [produceFor, setProduceFor] = useState<{ id: number; name: string; unit: string } | null>(null);
  const [produceQty, setProduceQty] = useState("");

  const invalidate = () => {
    qc.invalidateQueries({ queryKey: getListSemiFinishedQueryKey({ branchId: branchId! }) });
    qc.invalidateQueries({ queryKey: getListInventoryQueryKey({ branchId: branchId! }) });
  };

  const submitCreate = () => {
    if (!branchId) return;
    if (!name.trim() || !unit.trim()) { toast.error("Nama dan satuan wajib diisi"); return; }
    createSf.mutate(
      { data: { branchId, name: name.trim(), unit: unit.trim() } },
      {
        onSuccess: () => { toast.success("Item setengah jadi ditambahkan"); setOpen(false); setName(""); setUnit(""); invalidate(); },
        onError: () => toast.error("Gagal menambah item"),
      },
    );
  };

  const submitProduce = () => {
    if (!produceFor) return;
    const quantity = parseFloat(produceQty);
    if (!quantity || quantity <= 0) { toast.error("Jumlah harus lebih dari 0"); return; }
    produce.mutate(
      { id: produceFor.id, data: { quantity } },
      {
        onSuccess: () => { toast.success("Produksi berhasil, bahan baku terpotong"); setProduceFor(null); setProduceQty(""); invalidate(); },
        onError: (e) => toast.error(e instanceof Error ? e.message : "Gagal memproduksi"),
      },
    );
  };

  return (
    <ScrollArea className="h-full">
      <div className="p-6 space-y-3">
        <div className="flex justify-end">
          <Button size="sm" onClick={() => setOpen(true)}><Plus className="w-4 h-4 mr-1.5" />Tambah Item</Button>
        </div>
        {isLoading ? (
          [1, 2, 3].map((i) => <div key={i} className="h-14 rounded-lg bg-muted animate-pulse" />)
        ) : items.length === 0 ? (
          <Empty icon={FlaskConical} text="Belum ada item setengah jadi" />
        ) : (
          items.map((sf) => (
            <Card key={sf.id}>
              <CardContent className="p-4 flex items-center gap-4">
                <div className="w-9 h-9 rounded-lg bg-primary/10 text-primary flex items-center justify-center shrink-0"><FlaskConical className="w-4 h-4" /></div>
                <div className="flex-1 min-w-0">
                  <span className="font-medium">{sf.name}</span>
                  <p className="text-xs text-muted-foreground">HPP {formatRp(sf.costPricePerUnit)} / {sf.unit} · Stok {sf.currentStock}</p>
                </div>
                <Button size="sm" variant="ghost" onClick={() => setRecipeFor({ id: sf.id, name: sf.name })}><ChefHat className="w-4 h-4 mr-1.5" />Resep</Button>
                <Button size="sm" variant="outline" onClick={() => setProduceFor({ id: sf.id, name: sf.name, unit: sf.unit })}><PackagePlus className="w-4 h-4 mr-1.5" />Produksi</Button>
              </CardContent>
            </Card>
          ))
        )}
      </div>

      <Dialog open={open} onOpenChange={setOpen}>
        <DialogContent>
          <DialogHeader><DialogTitle>Tambah Item Setengah Jadi</DialogTitle></DialogHeader>
          <div className="space-y-4 py-2">
            <div className="space-y-1.5"><label className="text-sm font-medium">Nama</label><Input value={name} onChange={(e) => setName(e.target.value)} placeholder="cth. Adonan Roti" autoFocus /></div>
            <div className="space-y-1.5"><label className="text-sm font-medium">Satuan</label><Input value={unit} onChange={(e) => setUnit(e.target.value)} placeholder="cth. porsi, batch" /></div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setOpen(false)}>Batal</Button>
            <Button onClick={submitCreate} disabled={createSf.isPending}>{createSf.isPending ? "Menyimpan..." : "Simpan"}</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog open={!!produceFor} onOpenChange={(o) => !o && setProduceFor(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Produksi — {produceFor?.name}</DialogTitle>
            <DialogDescription>Memproduksi akan memotong stok bahan baku sesuai resep dan menambah stok item ini.</DialogDescription>
          </DialogHeader>
          <div className="space-y-1.5 py-2">
            <label className="text-sm font-medium">Jumlah Produksi ({produceFor?.unit})</label>
            <Input type="number" value={produceQty} onChange={(e) => setProduceQty(e.target.value)} placeholder="0" autoFocus />
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setProduceFor(null)}>Batal</Button>
            <Button onClick={submitProduce} disabled={produce.isPending}>{produce.isPending ? "Memproses..." : "Produksi"}</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {recipeFor && branchId && (
        <RecipeDialog
          parentType="semi_finished"
          parentId={recipeFor.id}
          parentName={recipeFor.name}
          branchId={branchId}
          onClose={() => setRecipeFor(null)}
        />
      )}
    </ScrollArea>
  );
}

export function RecipeDialog({
  parentType, parentId, parentName, branchId, onClose,
}: {
  parentType: SetRecipeInputParentType;
  parentId: number;
  parentName: string;
  branchId: number;
  onClose: () => void;
}) {
  const qc = useQueryClient();
  const { data: existing = [], isLoading } = useGetRecipe({ parentType, parentId });
  const { data: ingredients = [] } = useListIngredients({ branchId });
  const { data: semiFinished = [] } = useListSemiFinished({ branchId });
  const setRecipe = useSetRecipe();
  const [rows, setRows] = useState<SetRecipeInputComponentsItem[] | null>(null);

  const components: SetRecipeInputComponentsItem[] =
    rows ?? existing.map((c) => ({ componentType: c.componentType, componentId: c.componentId, quantity: c.quantity }));

  const update = (next: SetRecipeInputComponentsItem[]) => setRows(next);

  const options = [
    ...ingredients.map((i) => ({ type: "ingredient" as const, id: i.id, name: i.name, unit: i.unit })),
    ...semiFinished.filter((s) => !(parentType === "semi_finished" && s.id === parentId)).map((s) => ({ type: "semi_finished" as const, id: s.id, name: s.name, unit: s.unit })),
  ];

  const addRow = () => {
    if (!options.length) { toast.error("Tambah bahan baku terlebih dahulu"); return; }
    update([...components, { componentType: options[0].type, componentId: options[0].id, quantity: 1 }]);
  };

  const save = () => {
    setRecipe.mutate(
      { data: { parentType, parentId, components } },
      {
        onSuccess: () => {
          toast.success("Resep disimpan");
          qc.invalidateQueries({ queryKey: getListInventoryQueryKey({ branchId }) });
          qc.invalidateQueries({ queryKey: getListSemiFinishedQueryKey({ branchId }) });
          onClose();
        },
        onError: () => toast.error("Gagal menyimpan resep"),
      },
    );
  };

  return (
    <Dialog open onOpenChange={(o) => !o && onClose()}>
      <DialogContent className="max-w-lg">
        <DialogHeader>
          <DialogTitle>Resep (BOM) — {parentName}</DialogTitle>
          <DialogDescription>Tentukan bahan & jumlah yang dipakai untuk 1 unit. HPP dihitung otomatis dari resep ini.</DialogDescription>
        </DialogHeader>
        <div className="space-y-3 py-2 max-h-[50vh] overflow-y-auto">
          {isLoading ? (
            <div className="h-20 bg-muted rounded animate-pulse" />
          ) : components.length === 0 ? (
            <p className="text-sm text-muted-foreground text-center py-6">Belum ada komponen. Klik "Tambah Komponen".</p>
          ) : (
            components.map((row, idx) => {
              const key = `${row.componentType}:${row.componentId}`;
              return (
                <div key={idx} className="flex gap-2 items-center">
                  <Select
                    value={key}
                    onValueChange={(v) => {
                      const [t, id] = v.split(":");
                      const next = [...components];
                      next[idx] = { ...row, componentType: t as SetRecipeInputComponentsItem["componentType"], componentId: Number(id) };
                      update(next);
                    }}
                  >
                    <SelectTrigger className="flex-1"><SelectValue /></SelectTrigger>
                    <SelectContent>
                      {options.map((o) => (
                        <SelectItem key={`${o.type}:${o.id}`} value={`${o.type}:${o.id}`}>
                          {o.name} {o.type === "semi_finished" ? "(setengah jadi)" : ""} — {o.unit}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  <Input
                    type="number"
                    className="w-24"
                    value={row.quantity}
                    onChange={(e) => {
                      const next = [...components];
                      next[idx] = { ...row, quantity: parseFloat(e.target.value) || 0 };
                      update(next);
                    }}
                  />
                  <Button variant="ghost" size="icon" onClick={() => update(components.filter((_, i) => i !== idx))}>
                    <Trash2 className="w-4 h-4 text-destructive" />
                  </Button>
                </div>
              );
            })
          )}
          <Button variant="outline" size="sm" onClick={addRow}><Plus className="w-4 h-4 mr-1.5" />Tambah Komponen</Button>
        </div>
        <DialogFooter>
          <Button variant="outline" onClick={onClose}>Batal</Button>
          <Button onClick={save} disabled={setRecipe.isPending}>{setRecipe.isPending ? "Menyimpan..." : "Simpan Resep"}</Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

function Empty({ icon: Icon, text }: { icon: React.ElementType; text: string }) {
  return (
    <div className="py-16 text-center text-muted-foreground">
      <Icon className="w-10 h-10 mx-auto mb-2 opacity-20" />
      <p className="text-sm">{text}</p>
    </div>
  );
}

import React, { useEffect, useRef, useState } from "react";
import { useQueryClient } from "@tanstack/react-query";
import {
  useGetExpectedStock,
  useCreateShiftAudit,
  useRequestUploadUrl,
  useGetMe,
  getListShiftAuditsQueryKey,
  getListInventoryQueryKey,
} from "@workspace/api-client-react";
import type { InventoryItem, ShiftAuditStockEntry } from "@workspace/api-client-react/src/generated/api.schemas";
import { useBranch } from "@/lib/branch";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent } from "@/components/ui/card";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Badge } from "@/components/ui/badge";
import { toast } from "sonner";
import { Camera, RefreshCw, Check, ClipboardList, FlaskConical, Package } from "lucide-react";

export default function ShiftPage() {
  const qc = useQueryClient();
  const { branchId, currentBranch } = useBranch();
  const { data: me } = useGetMe();
  const { data: expected = [], isLoading } = useGetExpectedStock(
    branchId ? { branchId } : undefined,
    { query: { enabled: branchId != null } },
  );
  const createAudit = useCreateShiftAudit();
  const requestUpload = useRequestUploadUrl();

  const [counts, setCounts] = useState<Record<string, string>>({});
  const [notes, setNotes] = useState("");
  const [photoBlob, setPhotoBlob] = useState<Blob | null>(null);
  const [photoUrl, setPhotoUrl] = useState<string | null>(null);
  const [cameraOn, setCameraOn] = useState(false);
  const [uploading, setUploading] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const keyOf = (it: InventoryItem) => `${it.itemType}:${it.itemId}`;

  useEffect(() => {
    return () => stopCamera();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: "environment" }, audio: false });
      streamRef.current = stream;
      setCameraOn(true);
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        await videoRef.current.play();
      }
    } catch {
      toast.error("Tidak bisa mengakses kamera. Izinkan akses kamera di browser.");
    }
  };

  const stopCamera = () => {
    streamRef.current?.getTracks().forEach((t) => t.stop());
    streamRef.current = null;
    setCameraOn(false);
  };

  const capture = () => {
    const video = videoRef.current;
    if (!video) return;
    const canvas = document.createElement("canvas");
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;
    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    canvas.toBlob((blob) => {
      if (!blob) return;
      setPhotoBlob(blob);
      setPhotoUrl(URL.createObjectURL(blob));
      stopCamera();
    }, "image/jpeg", 0.85);
  };

  const retake = () => {
    if (photoUrl) URL.revokeObjectURL(photoUrl);
    setPhotoBlob(null);
    setPhotoUrl(null);
    startCamera();
  };

  const uploadPhoto = async (): Promise<string | null> => {
    if (!photoBlob) return null;
    const res = await requestUpload.mutateAsync({
      data: { name: `shift-proof-${Date.now()}.jpg`, size: photoBlob.size, contentType: "image/jpeg" },
    });
    const putRes = await fetch(res.uploadURL, {
      method: "PUT",
      headers: { "Content-Type": "image/jpeg" },
      body: photoBlob,
    });
    if (!putRes.ok) throw new Error("Upload gagal");
    return res.objectPath;
  };

  const submit = async () => {
    if (!branchId) return;
    if (!photoBlob) { toast.error("Ambil foto bukti stok terlebih dahulu"); return; }
    const actualStock: ShiftAuditStockEntry[] = expected.map((it) => ({
      itemType: it.itemType,
      itemId: it.itemId,
      name: it.name,
      unit: it.unit,
      quantity: parseFloat(counts[keyOf(it)] ?? "") || 0,
    }));
    setUploading(true);
    try {
      const photoProofUrl = await uploadPhoto();
      await createAudit.mutateAsync({
        data: {
          branchId,
          cashierId: me?.id ?? null,
          actualStock,
          photoProofUrl,
          notes: notes || null,
        },
      });
      toast.success("Tutup shift berhasil dikirim untuk audit");
      setCounts({}); setNotes(""); setPhotoBlob(null);
      if (photoUrl) URL.revokeObjectURL(photoUrl);
      setPhotoUrl(null);
      qc.invalidateQueries({ queryKey: getListShiftAuditsQueryKey({ branchId }) });
      qc.invalidateQueries({ queryKey: getListInventoryQueryKey({ branchId }) });
    } catch (e) {
      toast.error(e instanceof Error ? e.message : "Gagal mengirim tutup shift");
    } finally {
      setUploading(false);
    }
  };

  return (
    <div className="flex flex-col h-full">
      <div className="h-16 border-b px-6 flex items-center bg-card shrink-0">
        <h1 className="font-bold text-xl tracking-tight">Tutup Shift</h1>
        {currentBranch && <Badge variant="outline" className="ml-3 text-xs">{currentBranch.name}</Badge>}
      </div>

      <ScrollArea className="flex-1">
        <div className="p-6 grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="lg:col-span-2 space-y-4">
            <Card>
              <CardContent className="p-4">
                <div className="flex items-center gap-2 mb-3">
                  <ClipboardList className="w-4 h-4 text-primary" />
                  <h2 className="font-semibold">Hitung Stok Fisik</h2>
                </div>
                <p className="text-xs text-muted-foreground mb-4">
                  Sistem sudah menghitung stok seharusnya (POS). Masukkan jumlah fisik hasil hitung manual Anda.
                </p>
                {isLoading ? (
                  <div className="space-y-2">{[1, 2, 3].map((i) => <div key={i} className="h-12 bg-muted rounded animate-pulse" />)}</div>
                ) : expected.length === 0 ? (
                  <p className="text-sm text-muted-foreground py-6 text-center">Belum ada bahan/stok untuk dihitung.</p>
                ) : (
                  <div className="space-y-2">
                    {expected.map((it) => (
                      <div key={keyOf(it)} className="flex items-center gap-3 p-2 rounded-lg border">
                        <div className="w-8 h-8 rounded bg-primary/10 text-primary flex items-center justify-center shrink-0">
                          {it.itemType === "semi_finished" ? <FlaskConical className="w-4 h-4" /> : <Package className="w-4 h-4" />}
                        </div>
                        <div className="flex-1 min-w-0">
                          <span className="text-sm font-medium truncate block">{it.name}</span>
                          <span className="text-[11px] text-muted-foreground">Seharusnya (POS): {it.currentStock} {it.unit}</span>
                        </div>
                        <Input
                          type="number"
                          className="w-28"
                          placeholder="Fisik"
                          value={counts[keyOf(it)] ?? ""}
                          onChange={(e) => setCounts((p) => ({ ...p, [keyOf(it)]: e.target.value }))}
                        />
                      </div>
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>

            <Card>
              <CardContent className="p-4 space-y-2">
                <label className="text-sm font-medium">Catatan</label>
                <Input value={notes} onChange={(e) => setNotes(e.target.value)} placeholder="Opsional — cth. tumpah, rusak, dll" />
              </CardContent>
            </Card>
          </div>

          <div className="space-y-4">
            <Card>
              <CardContent className="p-4">
                <div className="flex items-center gap-2 mb-3">
                  <Camera className="w-4 h-4 text-primary" />
                  <h2 className="font-semibold">Foto Bukti</h2>
                </div>
                <div className="aspect-[3/4] rounded-lg bg-muted overflow-hidden flex items-center justify-center mb-3">
                  {photoUrl ? (
                    <img src={photoUrl} alt="Bukti stok" className="w-full h-full object-cover" />
                  ) : cameraOn ? (
                    <video ref={videoRef} playsInline muted className="w-full h-full object-cover" />
                  ) : (
                    <div className="text-center text-muted-foreground p-4">
                      <Camera className="w-10 h-10 mx-auto mb-2 opacity-30" />
                      <p className="text-xs">Ambil foto stok sebagai bukti audit</p>
                    </div>
                  )}
                </div>
                {photoUrl ? (
                  <Button variant="outline" className="w-full" onClick={retake}><RefreshCw className="w-4 h-4 mr-1.5" />Ambil Ulang</Button>
                ) : cameraOn ? (
                  <Button className="w-full" onClick={capture}><Camera className="w-4 h-4 mr-1.5" />Jepret</Button>
                ) : (
                  <Button variant="outline" className="w-full" onClick={startCamera}><Camera className="w-4 h-4 mr-1.5" />Buka Kamera</Button>
                )}
              </CardContent>
            </Card>

            <Button
              className="w-full h-12 text-base font-bold"
              onClick={submit}
              disabled={uploading || createAudit.isPending || isLoading}
            >
              {uploading || createAudit.isPending ? "Mengirim..." : <><Check className="w-5 h-5 mr-1.5" />Kirim Tutup Shift</>}
            </Button>
          </div>
        </div>
      </ScrollArea>
    </div>
  );
}

import { useState } from "react";
import { useQueryClient } from "@tanstack/react-query";
import {
  useListShiftAudits,
  useGetShiftAudit,
  useVerifyShiftAudit,
  getListShiftAuditsQueryKey,
  getGetShiftAuditQueryKey,
} from "@workspace/api-client-react";
import type { ShiftAudit } from "@workspace/api-client-react/src/generated/api.schemas";
import { useBranch } from "@/lib/branch";
import { formatDate } from "@/lib/format";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Badge } from "@/components/ui/badge";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle,
} from "@/components/ui/dialog";
import { toast } from "sonner";
import { ClipboardCheck, AlertTriangle, CheckCircle2, Clock, ShieldCheck } from "lucide-react";

function statusBadge(status: string) {
  if (status === "verified") return <Badge className="bg-green-600 hover:bg-green-600"><CheckCircle2 className="w-3 h-3 mr-1" />Terverifikasi</Badge>;
  if (status === "discrepancy") return <Badge variant="destructive"><AlertTriangle className="w-3 h-3 mr-1" />Selisih</Badge>;
  return <Badge variant="secondary"><Clock className="w-3 h-3 mr-1" />Menunggu</Badge>;
}

export default function AuditsPage() {
  const { branchId, currentBranch } = useBranch();
  const { data: audits = [], isLoading } = useListShiftAudits(
    branchId ? { branchId } : undefined,
    { query: { enabled: branchId != null } },
  );
  const [selected, setSelected] = useState<ShiftAudit | null>(null);

  return (
    <div className="flex flex-col h-full">
      <div className="h-16 border-b px-6 flex items-center bg-card shrink-0">
        <h1 className="font-bold text-xl tracking-tight">Audit Shift</h1>
        {currentBranch && <Badge variant="outline" className="ml-3 text-xs">{currentBranch.name}</Badge>}
      </div>

      <ScrollArea className="flex-1">
        <div className="p-6 space-y-3">
          {isLoading ? (
            [1, 2, 3].map((i) => <div key={i} className="h-20 rounded-lg bg-muted animate-pulse" />)
          ) : audits.length === 0 ? (
            <div className="py-16 text-center text-muted-foreground">
              <ClipboardCheck className="w-10 h-10 mx-auto mb-2 opacity-20" />
              <p className="text-sm">Belum ada tutup shift untuk diaudit</p>
            </div>
          ) : (
            audits.map((a) => (
              <Card key={a.id} className="cursor-pointer hover:ring-2 hover:ring-primary transition-all" onClick={() => setSelected(a)}>
                <CardContent className="p-4 flex items-center gap-4">
                  <div className="w-10 h-10 rounded-lg bg-primary/10 text-primary flex items-center justify-center shrink-0">
                    <ClipboardCheck className="w-5 h-5" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2">
                      <span className="font-medium">{a.cashierName ?? "Kasir"}</span>
                      {statusBadge(a.status)}
                    </div>
                    <p className="text-xs text-muted-foreground mt-0.5">
                      {a.shiftEnd ? formatDate(a.shiftEnd) : "—"}
                    </p>
                  </div>
                  <Button variant="ghost" size="sm">Periksa</Button>
                </CardContent>
              </Card>
            ))
          )}
        </div>
      </ScrollArea>

      {selected && branchId && (
        <AuditDetailDialog auditId={selected.id} branchId={branchId} onClose={() => setSelected(null)} />
      )}
    </div>
  );
}

function AuditDetailDialog({ auditId, branchId, onClose }: { auditId: number; branchId: number; onClose: () => void }) {
  const qc = useQueryClient();
  const { data: detail, isLoading } = useGetShiftAudit(auditId);
  const verify = useVerifyShiftAudit();

  const recon = detail?.reconciliation ?? [];
  const hasWarning = recon.some((r) => r.isWarning);

  const onVerify = () => {
    verify.mutate(
      { id: auditId },
      {
        onSuccess: () => {
          toast.success("Audit terverifikasi");
          qc.invalidateQueries({ queryKey: getListShiftAuditsQueryKey({ branchId }) });
          qc.invalidateQueries({ queryKey: getGetShiftAuditQueryKey(auditId) });
        },
        onError: () => toast.error("Gagal memverifikasi audit"),
      },
    );
  };

  return (
    <Dialog open onOpenChange={(o) => !o && onClose()}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-hidden flex flex-col">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            Detail Audit — {detail?.cashierName ?? "Kasir"}
            {detail && statusBadge(detail.status)}
          </DialogTitle>
        </DialogHeader>

        {isLoading || !detail ? (
          <div className="h-64 bg-muted rounded animate-pulse" />
        ) : (
          <div className="flex-1 overflow-y-auto space-y-4">
            {hasWarning && (
              <div className="flex items-start gap-3 p-3 rounded-lg border border-destructive/40 bg-destructive/10 text-destructive">
                <AlertTriangle className="w-5 h-5 shrink-0 mt-0.5" />
                <div>
                  <p className="font-semibold text-sm">WARNING: Selisih melebihi 5%</p>
                  <p className="text-xs">Terdapat item dengan selisih signifikan antara stok POS dan stok fisik. Periksa sebelum memverifikasi.</p>
                </div>
              </div>
            )}

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <h3 className="text-sm font-semibold mb-2">Rekonsiliasi Stok</h3>
                <div className="border rounded-lg overflow-hidden">
                  <div className="grid grid-cols-12 gap-1 px-3 py-2 bg-muted text-[11px] font-medium text-muted-foreground">
                    <span className="col-span-5">Item</span>
                    <span className="col-span-2 text-right">POS</span>
                    <span className="col-span-2 text-right">Fisik</span>
                    <span className="col-span-3 text-right">Selisih</span>
                  </div>
                  {recon.length === 0 ? (
                    <p className="text-xs text-muted-foreground p-3 text-center">Tidak ada data stok.</p>
                  ) : (
                    recon.map((r) => (
                      <div key={`${r.itemType}-${r.itemId}`} className={`grid grid-cols-12 gap-1 px-3 py-2 text-xs border-t items-center ${r.isWarning ? "bg-destructive/5" : ""}`}>
                        <span className="col-span-5 truncate font-medium">{r.name}</span>
                        <span className="col-span-2 text-right">{r.expected}</span>
                        <span className="col-span-2 text-right">{r.actual}</span>
                        <span className={`col-span-3 text-right font-semibold ${r.isWarning ? "text-destructive" : r.diff === 0 ? "text-muted-foreground" : ""}`}>
                          {r.diff > 0 ? "+" : ""}{r.diff} ({r.diffPct.toFixed(1)}%)
                          {r.isWarning && <AlertTriangle className="w-3 h-3 inline ml-1" />}
                        </span>
                      </div>
                    ))
                  )}
                </div>
                {detail.notes && <p className="text-xs text-muted-foreground mt-2">Catatan: {detail.notes}</p>}
              </div>

              <div>
                <h3 className="text-sm font-semibold mb-2">Foto Bukti</h3>
                {detail.photoProofUrl ? (
                  <a href={`/api/storage${detail.photoProofUrl}`} target="_blank" rel="noreferrer">
                    <img src={`/api/storage${detail.photoProofUrl}`} alt="Bukti stok" className="w-full rounded-lg border object-cover max-h-72" />
                  </a>
                ) : (
                  <div className="h-40 rounded-lg border bg-muted flex items-center justify-center text-xs text-muted-foreground">
                    Tidak ada foto bukti
                  </div>
                )}
              </div>
            </div>

            <div className="flex justify-end gap-2 pt-2 border-t">
              <Button variant="outline" onClick={onClose}>Tutup</Button>
              {detail.status !== "verified" && (
                <Button onClick={onVerify} disabled={verify.isPending} className={hasWarning ? "bg-destructive hover:bg-destructive/90" : ""}>
                  <ShieldCheck className="w-4 h-4 mr-1.5" />
                  {verify.isPending ? "Memverifikasi..." : hasWarning ? "Verifikasi (ada warning)" : "Verifikasi"}
                </Button>
              )}
            </div>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

