    29→/** Upsert current_inventory by delta (can be negative). Returns the new stock level. */
    30→export async function adjustInventory(
    31→  tx: Executor,
    32→  branchId: number,
    33→  itemType: ItemType,
    34→  itemId: number,
    35→  delta: number,
    36→): Promise<number> {
    37→  const [existing] = await tx
    38→    .select()
    39→    .from(currentInventoryTable)
    40→    .where(
    41→      and(
    42→        eq(currentInventoryTable.branchId, branchId),
    43→        eq(currentInventoryTable.itemType, itemType),
    44→        eq(currentInventoryTable.itemId, itemId),
    45→      ),
    46→    );
    47→
    48→  if (!existing) {
    49→    const newStock = Math.max(0, delta);
    50→    await tx.insert(currentInventoryTable).values({
    51→      branchId,
    52→      itemType,
    53→      itemId,
    54→      currentStock: String(newStock),
    55→    });
    56→    return newStock;
    57→  }
    58→
    59→  const newStock = Math.max(0, parseFloat(existing.currentStock) + delta);
    60→  await tx
    61→    .update(currentInventoryTable)
    62→    .set({ currentStock: String(newStock) })
    63→    .where(eq(currentInventoryTable.id, existing.id));
    64→  return newStock;
    65→}
