    86→/**
    87→ * Moving average for raw materials on stock-in.
    88→ * new_cost = ((oldStock * oldPrice) + purchaseTotal) / (oldStock + newQty)
    89→ */
    90→export async function applyMovingAverage(
    91→  tx: Executor,
    92→  branchId: number,
    93→  ingredientId: number,
    94→  newQty: number,
    95→  purchaseTotal: number,
    96→): Promise<number> {
    97→  const [ing] = await tx
    98→    .select()
    99→    .from(ingredientsTable)
   100→    .where(eq(ingredientsTable.id, ingredientId));
   101→  if (!ing) return 0;
   102→
   103→  const oldStock = await getInventoryStock(tx, branchId, "ingredient", ingredientId);
   104→  const oldPrice = parseFloat(ing.costPricePerUnit);
   105→  const denom = oldStock + newQty;
   106→  const newCost = denom > 0 ? (oldStock * oldPrice + purchaseTotal) / denom : oldPrice;
   107→
   108→  await tx
   109→    .update(ingredientsTable)
   110→    .set({ costPricePerUnit: String(newCost) })
   111→    .where(eq(ingredientsTable.id, ingredientId));
   112→
   113→  return newCost;
   114→}
