   138→/**
   139→ * COGS for one unit of a parent = sum(component unit cost * recipe qty).
   140→ */
   141→export async function computeUnitCogs(
   142→  tx: Executor,
   143→  parentType: "product" | "semi_finished",
   144→  parentId: number,
   145→): Promise<number> {
   146→  const rows = await getRecipeRows(tx, parentType, parentId);
   147→  let cost = 0;
   148→  for (const r of rows) {
   149→    const unitCost = await getUnitCost(tx, r.componentType, r.componentId);
   150→    cost += unitCost * r.quantity;
   151→  }
   152→  return cost;
   153→}
   154→
   155→/**
   156→ * Deduct direct recipe components for selling `qty` of a product.
   157→ * Returns total COGS of the deducted components.
   158→ */
   159→export async function deductForProduct(
   160→  tx: Executor,
   161→  branchId: number,
   162→  productId: number,
   163→  qty: number,
   164→): Promise<number> {
   165→  const rows = await getRecipeRows(tx, "product", productId);
   166→  let cogs = 0;
   167→  for (const r of rows) {
   168→    const deductQty = r.quantity * qty;
   169→    const unitCost = await getUnitCost(tx, r.componentType, r.componentId);
   170→    cogs += unitCost * deductQty;
   171→    await adjustInventory(tx, branchId, r.componentType, r.componentId, -deductQty);
   172→  }
   173→  return cogs;
   174→}
