    .update(ingredientsTable)
    .set(update)
    .where(eq(ingredientsTable.id, id))
    .returning();
  if (!updated) {
    res.status(404).json({ error: "Not found" });
    return;
  }
  res.json({
    ...updated,
    costPricePerUnit: parseFloat(updated.costPricePerUnit),
    minimalStock: parseFloat(updated.minimalStock),
    currentStock: 0,
  });
});

