   127→  if (price !== undefined) update["price"] = String(price);
   128→  if (stock !== undefined) update["stock"] = stock;
   129→  if (imageUrl !== undefined) update["imageUrl"] = imageUrl;
   130→  if (isActive !== undefined) update["isActive"] = isActive;
   131→
   132→  if (Object.keys(update).length === 0) {
   133→    res.status(400).json({ error: "No fields to update" });
   134→    return;
   135→  }
   136→
   137→  const [prod] = await db.update(productsTable).set(update).where(eq(productsTable.id, id)).returning();
   138→  if (!prod) {
   139→    res.status(404).json({ error: "Not found" });
   140→    return;
   141→  }
